import{_ as t,o as i,c as o,j as e,a6 as s,em as r,en as n}from"./chunks/framework.UYVGz2W_.js";const b=JSON.parse('{"title":"Kitsu Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),l={name:"index.md"},u=r+"#logo-kitsu",h=n+"#logo-cgwire";function d(c,a,p,m,f,w){return i(),o("div",null,[...a[0]||(a[0]=[e("p",null,[e("img",{src:u,alt:"Kitsu Banner"})],-1),s('<h1 id="kitsu-documentation" tabindex="-1">Kitsu Documentation <a class="header-anchor" href="#kitsu-documentation" aria-label="Permalink to “Kitsu Documentation”">​</a></h1><p><a href="https://cg-wire.com/kitsu" target="_blank" rel="noreferrer">Kitsu</a> is a collaboration platform for animation and VFX productions. Through its clean UI and shared database, it connects all relevant stakeholders throughout the production process, including artists, production managers, supervisors, vendors, and clients.</p><h3 id="introduction-to-kitsu" tabindex="-1">Introduction to Kitsu <a class="header-anchor" href="#introduction-to-kitsu" aria-label="Permalink to “Introduction to Kitsu”">​</a></h3><p>Here are some links to familiarize yourself with the basic concepts in Kitsu you&#39;ll need to be successful with your production.</p><ul><li><a href="./configure-kitsu/">Getting Started With Kitsu</a>: learn key principles and common vocabulary terms used within Kitsu to better plan your production workflow.</li><li><a href="./team/">Preparing Your Team</a>: Prepare your team members and define their departments and permissions.</li></ul><h3 id="create-your-production" tabindex="-1">Create Your Production <a class="header-anchor" href="#create-your-production" aria-label="Permalink to “Create Your Production”">​</a></h3><p>Below you can find guides tailored to the specific type of production you are looking to create.</p><ul><li><a href="./tvshow/">Create a TV Show Production</a> Create a TV show production with assets, shots, sequences, episodes and edits</li><li><a href="./feature/">Create a Feature Film Production</a> Create a feature film production (approximately 1 000 entities) with assets, shots, sequences and edit.</li><li><a href="./short/">Create a SHORT Production</a>: Create a short production (approximately 500 assets and shots) with assets, shots, sequences and edit.</li><li><a href="./short-shot/">Create a SHOTS Only Production</a> Create a short production (about 500 shots) with only shots, sequences and edit</li><li><a href="./short-asset/">Create an ASSET Only Production</a> Create a short production (about 500 assets) with only assets.</li><li><a href="./videogame/">Create a Video Game Production</a> Create a Video game production with assets, Maps, Level and Chapters (as tv show).</li><li><a href="./nft/">Create a NFT Collection</a> Create a NFT Collection with assets, and NFT Collection.</li></ul><h3 id="meta-columns-filters-production-settings" tabindex="-1">Meta Columns, Filters &amp; Production Settings <a class="header-anchor" href="#meta-columns-filters-production-settings" aria-label="Permalink to “Meta Columns, Filters &amp; Production Settings”">​</a></h3><ul><li><a href="./meta-column/">Meta Columns</a>: Learn how to create and organize metadata from your production.</li><li><a href="./filter/">Filters</a>: Hone in on key information with powerful search functionality</li><li><a href="./configure-prod/">Production Specific Workflow Settings</a>: Tweak your specific production to your liking with various powerful settings.</li></ul><h3 id="assignments-estimates-and-scheduling" tabindex="-1">Assignments, Estimates and Scheduling <a class="header-anchor" href="#assignments-estimates-and-scheduling" aria-label="Permalink to “Assignments, Estimates and Scheduling”">​</a></h3><p>In this section, we will explain some of Kitsu&#39;s main use cases:</p><ul><li><a href="./assignation/">Task Assignments</a>: Learn how to add someone to a team and assign them to a task.</li><li><a href="./estimation/">Estimates &amp; Team Quotas</a>: Learn how to calculate the number of days estimated to do a task (bids) and check your team&#39;s efficiency.</li><li><a href="./schedules/">Schedules</a>: Discover the different scheduling capabilities in Kitsu, from the studio level to the task level.</li></ul><h3 id="statuses-publishes-and-thumbnails" tabindex="-1">Statuses, Publishes and Thumbnails <a class="header-anchor" href="#statuses-publishes-and-thumbnails" aria-label="Permalink to “Statuses, Publishes and Thumbnails”">​</a></h3><p>How keep your work organized, and your team updated on it&#39;s progress</p><ul><li><a href="/status/">Statuses &amp; Feedback</a>: How to change statuses and keep your team updated on the progress of work.</li><li><a href="/publish/">Publishes</a>: How to publish and share work with your team.</li><li><a href="/thumbnails/">Thumbnails</a>: How to apply thumbnails to assets and shots.</li></ul><h3 id="internal-review-and-client-playlists" tabindex="-1">Internal Review and Client Playlists <a class="header-anchor" href="#internal-review-and-client-playlists" aria-label="Permalink to “Internal Review and Client Playlists”">​</a></h3><p>How to organize internal and external reviews:</p><ul><li><a href="./review/">Reviews</a>: Learn how to review all feedback on a task.</li><li><a href="./review-weekly/">Daily &amp; Weekly Review</a>: Quickly gather video versions and stay focused during the review.</li><li><a href="./playlist-client/">Client Playlists</a>: Collect and share your work with your client in a managed environment.</li></ul><h3 id="supervisor-workflows" tabindex="-1">Supervisor Workflows <a class="header-anchor" href="#supervisor-workflows" aria-label="Permalink to “Supervisor Workflows”">​</a></h3><p>As a supervisor, your uses cases when using Kitsu may differ than your production team.</p><ul><li><a href="./supervisor-team/">Managing Your Department</a>: Discover methods for effectively managing and overseeing your team.</li><li><a href="./supervisor-tasks/">Task Supervision</a>: Learn how to stay on top of task assignments.</li></ul><h3 id="producer-workflows" tabindex="-1">Producer Workflows <a class="header-anchor" href="#producer-workflows" aria-label="Permalink to “Producer Workflows”">​</a></h3><p>As a producer, mastering the ability to zoom out from specifics to a holistic view is essential.</p><ul><li><a href="./production-report/">Building Production Reports</a>: Learn everything you need to know to create your production reports.</li><li><a href="./studio-report/">Building Studio Reports</a>: Ensure you&#39;re ahead of the game with your studio&#39;s productions.</li></ul><h3 id="developer-workflows" tabindex="-1">Developer Workflows <a class="header-anchor" href="#developer-workflows" aria-label="Permalink to “Developer Workflows”">​</a></h3><p>As a developer, explore some of the possibilities for extending and integrating Kitsu within your studio&#39;s pipeline.</p><ul><li><a href="./custom-actions/">Custom Actions</a>: A custom action is a simple HTTP request that sends information from your current Kitsu selection to a custom end.</li><li><a href="./bots/">Bots</a>: The main use is for scripting with gazu (Kitsu&#39;s Python Client), and anything else that can use our API.</li><li><a href="./publisher/">Kitsu Publisher</a>: A web application used to share the progress of your productions and validate your deliveries.</li><li><a href="./chat-integration/">Chat Integration</a>: Get Kitsu notifications sent directly to popular messaging apps like Discord, Slack or Mattermost.</li><li><a href="./installation/">Open Source Setup</a>: Learn about how you can self-deploy a host a local version of Kitsu within your studio&#39;s environment.</li></ul><h3 id="tutorials" tabindex="-1">Tutorials <a class="header-anchor" href="#tutorials" aria-label="Permalink to “Tutorials”">​</a></h3><p>Access comprehensive video tutorials on YouTube, highlighting crucial functionalities of Kitsu. Click the link below to view.</p><p><a href="https://www.youtube.com/playlist?list=PLp_1gB5ZBHXqnQgZ4TCrAt7smxesaDo29" target="_blank" rel="noreferrer">Kitsu Tutorials Channel</a></p><h3 id="about-the-authors" tabindex="-1">About the Authors <a class="header-anchor" href="#about-the-authors" aria-label="Permalink to “About the Authors”">​</a></h3><p>Kitsu is written by CG Wire, a company based in France. We help animation studios to manage their productions and build efficient pipelines.</p><p>We adhere to software craftsmanship principles whenever feasible. Our passion for coding is reflected in our commitment to delivering robust quality and providing an exceptional developer experience. With our extensive expertise, we help studios navigate the complexities of production, fostering more efficient collaboration, quicker delivery, resulting in better pictures.</p><p>Visit <a href="https://cg-wire.com" target="_blank" rel="noreferrer">cg-wire.com</a> for more information.</p>',35),e("p",null,[e("a",{href:"https://cg-wire.com",target:"_blank",rel:"noreferrer"},[e("img",{src:h,alt:"CG Wire Logo"})])],-1)])])}const k=t(l,[["render",d]]);export{b as __pageData,k as default};
